public class CucumberTest {
}

package org.apache.commons.math3.dfp.steps;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;
import org.apache.commons.math3.dfp.Dfp;
import org.apache.commons.math3.dfp.DfpField;

import static org.junit.Assert.*;

public class StepDefs {
    private Dfp dfpValue;
    private Dfp result;
    private boolean invalidFlagRaised = false;
    private Exception exception;

    @Given("^I have a Dfp value of \"([^\"]*)\"$")
    public void i_have_a_Dfp_value_of(String value) throws Throwable {
        DfpField field = new DfpField(40); // 40 digits precision
        this.dfpValue = field.newInstance(value);
    }

    @When("^I multiply it by the integer (\\d+)$")
    public void i_multiply_it_by_the_integer(int multiplier) throws Throwable {
        try {
            this.result = dfpValue.multiply(multiplier);
            // Reset flag in case this is being called again
            invalidFlagRaised = (field.getIEEEFlags() & DfpField.FLAG_INVALID) != 0;
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("^the result should be \"([^\"]*)\"$")
    public void the_result_should_be(String expected) throws Throwable {
        assertNotNull("Result should not be null", result);
        Dfp expectedDfp = dfpValue.getField().newInstance(expected);
        assertEquals("Result should match expected value", expectedDfp.toString(), result.toString());
    }

    @Then("^the result should not be NaN$")
    public void the_result_should_not_be_NaN() throws Throwable {
        assertNotNull("Result should not be null", result);
        assertFalse("Result should not be NaN", result.isNaN());
    }

    @Then("^the operation should not raise an invalid flag$")
    public void the_operation_should_not_raise_an_invalid_flag() throws Throwable {
        assertFalse("Invalid flag should not be raised", invalidFlagRaised);
        if (exception != null) {
            fail("Exception was thrown: " + exception.getMessage());
        }
    }
}

